import{_ as t,o as i,c as n,ai as r}from"./chunks/framework.CaiDwmc7.js";const g=JSON.parse('{"title":"Getting Started with Bifröst","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),a={name:"guide/getting-started.md"};function o(l,e,s,d,c,h){return i(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="getting-started-with-bifrost" tabindex="-1">Getting Started with Bifröst <a class="header-anchor" href="#getting-started-with-bifrost" aria-label="Permalink to “Getting Started with Bifröst”">​</a></h1><p>This guide will help you get started with Bifröst, the bridge between Discord and Fluxer. Follow the instructions below to set up and configure Bifröst for your communities.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>For a guide to self host Bifröst, check out the <a href="/guide/self-hosting.html">Self Hosting Guide</a>.</p></div><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to “Installation”">​</a></h2><p>To install Bifröst, you can add it to your Discord and Fluxer servers using the following links:</p><ul><li><a href="https://discord.com/oauth2/authorize?client_id=1475436995697180845&amp;permissions=536947712&amp;integration_type=0&amp;scope=bot" target="_blank" rel="noreferrer">Add to Discord</a></li><li><a href="https://web.fluxer.app/oauth2/authorize?client_id=1475208219145040215&amp;scope=bot&amp;permissions=536947712" target="_blank" rel="noreferrer">Add to Fluxer</a></li></ul><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to “Configuration”">​</a></h2><h3 id="linking-your-servers" tabindex="-1">Linking Your Servers <a class="header-anchor" href="#linking-your-servers" aria-label="Permalink to “Linking Your Servers”">​</a></h3><p>After adding Bifröst to your servers, you first have to link your Discord and Fluxer server. To do this, use the <code>!b linkguild &lt;discord_guild_id&gt;</code> command in any channel on your Fluxer server. You can find your Discord guild ID by enabling Developer Mode in Discord&#39;s settings and right-clicking on your server.</p><p>Alternatively, you can link it from your Discord server by using the <code>!b linkguild &lt;fluxer_guild_id&gt;</code> command.</p><h3 id="linking-channels" tabindex="-1">Linking Channels <a class="header-anchor" href="#linking-channels" aria-label="Permalink to “Linking Channels”">​</a></h3><p>Once your servers are linked, you can link specific channels between the two platforms. Use the <code>!b linkchannel &lt;discord_channel_id&gt;</code> command to link the current Fluxer channel to a Discord channel. You can find the Discord channel ID by right-clicking on the channel in Discord and selecting &quot;Copy ID&quot;.</p><p>Alternatively, you can link it from your Discord server by using the <code>!b linkchannel &lt;fluxer_channel_id&gt;</code> command in the desired Discord channel.</p>',13)])])}const f=t(a,[["render",o]]);export{g as __pageData,f as default};
